// 

	      var channel, name, channelNum, channelName, channelShortName;

	      function init(){
	          //alert("VERSION 0.01");
	          setTimeout("init2()",1000);
	      }

	      function init2() {

	          if (getProperty("S", "Width") == "640") {
	              setProperty("PreloadPage", "width", "640");
	              setProperty("launchPanel", "left", "-107");
	          }
              channel=getProperty("FullScreenDS","channel");
              name=getProperty("FullScreenDS","stationShortName");
              if(channel=="9999"){
                  mediaDescriptor=getProperty("FullScreenDS","tuneUrl").split("mediadescriptor=")[1];
                  name=getProperty("DvrDS","byTitle/recorded/recording[@mediaDescriptor='"+mediaDescriptor+"']/@callLetters");
              }
              
              var a=getProperty("ChannelMapName","text");
              var b=(a.split("_"))[0];              
              name = name.toUpperCase();
              name = name.replace(/\s/g, "");
              name = name.replace(/HD/g, ""); 
              channelShortName = getProperty("VHOinfo", "//vhoMap/channel[@name='" + name + "']/@name");
              
               if(channelShortName!=name){
                   //alert("EXITING1");
                   invokeAction(null, "exit");
		       }
               invokeAction(null,"focus");
               invokeAction(null, "showButton");
               setTimeout("invokeAction(null, 'exit')", 7000);
               checkChannel();
           }
	
		   function checkChannel(){
		       channel=getProperty("FullScreenDS","channel");
		       name = getProperty("FullScreenDS", "stationShortName");
		       name = name.toUpperCase();
		       name = name.replace(/\s/g, "");
		       name = name.replace(/HD/g, "");
               if(channel=="9999"){mediaDescriptor=getProperty("FullScreenDS","tuneUrl").split("mediadescriptor=")[1];
                   channel=getProperty("DvrDS","byTitle/recorded/recording[@mediaDescriptor='"+mediaDescriptor+"']/@channel");
                   name = getProperty("DvrDS", "byTitle/recorded/recording[@mediaDescriptor='" + mediaDescriptor + "']/@callLetters");
                   if (name != channelShortName) {
                       invokeAction(null, "exit");
		            }
		        }

		        else{
		            if(name!=channelShortName){
		                invokeAction(null,"exit");
		            }
		        }
               setTimeout("checkChannel()",1000);
		   }

		   function goTo() {
		       alert("go... ");
		       var a = window.readContext("keyname");
		       if (a != "select") {
		           window.writeContext("handled", false);
		       } else {
		           if (a == "select") {
		               invokeAction(null, "hideButton");
		               window.writeContext("handled", true);
		               invokeAction(null, "Navigate", "https://renonaswsvip.asp.att.net/WAMSPresentation/MPFTemplateBuilder.aspx?id=6949&providerid=544&RemoveXRAWrapper=true&__MPFLayer=0");
		           }
		       }
		   }

